      "title": "Volunteer Digital Skills Online Class Instructor",
      "excerpt": "Note: while this is a non-paid, volunteer role, it can provide you with valuable experience for your resume and references from our organization if you are successful.",
      "companyName": "THE EDUCATIONAL EQUALITY INSTITUTE",
      "companySlug": "the-educational-equality-institute",
      "companyLogo": "https://cdn-images.himalayas.app/vw9k34ptj7xa34puce2f9zxb8h6b",
