export const fetchJobs = async (page = 1) => {
  // Simulate API delay
  await new Promise(resolve => setTimeout(resolve, 500));

  const startIndex = (page - 1) * 12;
  const endIndex = startIndex + 12;
  const paginatedJobs = dummyJobs.slice(startIndex, endIndex);

  // Add unique id to each job using guid
  const jobsWithIds = paginatedJobs.map(job => ({
    ...job,
    id: job.guid
  }));

  return {
    data: jobsWithIds,
    status: 'success'
  };
};
